func (q *Queries) ListPendingSync(ctx context.Context) ([]PendingSync, error) {
	rows, err := q.db.QueryContext(ctx, listPendingSync)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []PendingSync
	for rows.Next() {
		var i PendingSync
		if err := rows.Scan(
			&i.ID,
			&i.Operation,
			&i.EntityType,
			&i.EntityID,
			&i.Payload,
			&i.CreatedAt,
			&i.Attempts,
			&i.LastError,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

